import React, { useState } from "react";
import "./Department.css";

const DepartmentList = () => {
  const [departments, setDepartments] = useState([
    { id: 1, name: "IT", description: "Handles technical operations" },
    { id: 2, name: "HR", description: "Manages employees & HR operations" },
    { id: 3, name: "Finance", description: "Handles accounts & payroll" },
  ]);

  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const [department, setDepartment] = useState({
    name: "",
    description: "",
  });

  // Handle Input Change
  const handleChange = (e) => {
    setDepartment({ ...department, [e.target.name]: e.target.value });
  };

  // Open Add Form
  const handleAdd = () => {
    setDepartment({ name: "", description: "" });
    setEditingId(null);
    setShowForm(true);
  };

  // Open Edit Form
  const handleEdit = (dept) => {
    setDepartment({ name: dept.name, description: dept.description });
    setEditingId(dept.id);
    setShowForm(true);
  };

  // Save Department (Add or Update)
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!department.name.trim()) {
      alert("Department Name is required");
      return;
    }

    if (editingId) {
      // Update Department
      setDepartments(
        departments.map((d) =>
          d.id === editingId
            ? { ...d, name: department.name, description: department.description }
            : d
        )
      );
    } else {
      // Add New Department
      setDepartments([
        ...departments,
        {
          id: Date.now(),
          name: department.name,
          description: department.description,
        },
      ]);
    }

    setShowForm(false);
  };

  // Delete Department
  const handleDelete = (id) => {
    if (window.confirm("Are you sure to delete this department?")) {
      setDepartments(departments.filter((d) => d.id !== id));
    }
  };

  return (
    <div className="department-container">
      <h2>Manage Departments</h2>

      <button className="add-btn" onClick={handleAdd}>
        Add New Department
      </button>

      <table className="department-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Department Name</th>
            <th>Description</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {departments.map((dept, index) => (
            <tr key={dept.id}>
              <td>{index + 1}</td>
              <td>{dept.name}</td>
              <td>{dept.description}</td>
              <td>
                <button className="edit-btn" onClick={() => handleEdit(dept)}>
                  Edit
                </button>

                <button
                  className="delete-btn"
                  onClick={() => handleDelete(dept.id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}

          {departments.length === 0 && (
            <tr>
              <td colSpan="4" style={{ textAlign: "center" }}>
                No Departments Found
              </td>
            </tr>
          )}
        </tbody>
      </table>

      {/* FORM POPUP */}
      {showForm && (
        <div className="popup-overlay">
          <div className="popup-box">
            <h3>{editingId ? "Edit Department" : "Add New Department"}</h3>

            <form onSubmit={handleSubmit}>
              <label>Department Name</label>
              <input
                type="text"
                name="name"
                value={department.name}
                onChange={handleChange}
                placeholder="Enter department name"
                required
              />

              <label>Description</label>
              <textarea
                name="description"
                value={department.description}
                onChange={handleChange}
                placeholder="Enter description"
              />

              <div className="popup-actions">
                <button type="submit" className="save-btn">
                  {editingId ? "Update" : "Save"}
                </button>

                <button
                  type="button"
                  className="cancel-btn"
                  onClick={() => setShowForm(false)}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DepartmentList;
